SELECT moi.material_id AS materialId, ROUND(AVG(DATEDIFF(mi.inbound_date, mo.order_date)), 1) AS avgLeadDays, MAX(DATEDIFF(mi.inbound_date, mo.order_date)) AS maxLeadDays, COUNT(*) AS samples FROM material_order_item moi JOIN material_order mo ON mo.order_id = moi.order_id JOIN material_inbound_item mii ON mii.order_item_id = moi.order_item_id JOIN material_inbound mi ON mi.inbound_id = mii.inbound_id WHERE moi.material_id IN
#{id}
AND mo.order_date IS NOT NULL AND mi.inbound_date IS NOT NULL GROUP BY moi.material_id
